459→    public function extractSlots(Request $request): JsonResponse
460→    {
461→        $sfuserId = Arr::get($request->input('sfuser_info'), 'id');
462→        if (!$this->inWhitelist($sfuserId)) {
463→            return $this->responseJsonFail('无权限');
464→        }
465→
466→        $message = $request->input('message');
467→        $conversationId = $request->input('conversation_id', '');
468→        $availableGroups = $request->input('available_groups', []);
469→        $availableMembers = $request->input('available_members', []);
470→        $previousContext = $request->input('previous_context');
471→        $hasExistingContext = $request->boolean('has_existing_context', false);
472→
473→        $difyBaseUrl = env('DIFY_BASE_URL', 'http://10.61.0.11:10880/v1');
474→        $difyApiKey = env('DIFY_API_KEY', 'app-vfZMS4mxMLlWkoyb88PmGDfv');
475→        $difyUrl = rtrim($difyBaseUrl, '/').'/chat-messages';
476→
477→        // 将可用分组和成员列表格式化为 prompt 中的列表
478→        $groupList = !empty($availableGroups)
479→            ? implode("\n", array_map(fn ($g) => "   - {$g}", $availableGroups))
480→            : '   - （无可用分组）';
481→        $memberList = !empty($availableMembers)
482→            ? implode('、', $availableMembers)
483→            : '（无可用成员列表）';
484→        // 上次查询上下文：首次查询时为"无"，续查时包含上次的成员和周期
485→        $prevCtx = '无（首次查询）';
486→        if (!empty($previousContext)) {
487→            $prevMembers = implode('、', $previousContext['members'] ?? []);
488→            $prevType = ($previousContext['member_type'] ?? '') === 'group' ? '分组' : '成员';
489→            $prevPeriod = ($previousContext['period_start'] ?? '').' ~ '.($previousContext['period_end'] ?? '');
490→            $prevCtx = "上次查询{$prevType}：{$prevMembers}，周期：{$prevPeriod}";
491→        }
492→        $hasContextLabel = $hasExistingContext ? '是' : '否';
493→        $systemPrompt = sprintf(self::SLOT_EXTRACTION_PROMPT, $hasContextLabel, $groupList, $memberList, now()->toDateString(), $prevCtx);
494→
495→        $payload = json_encode([
496→            'inputs' => ['system_prompt' => $systemPrompt],
497→            'query' => $message,
498→            'response_mode' => 'blocking',
499→            'conversation_id' => $conversationId ?: '',
500→            'user' => 'oa-slots-'.$sfuserId,
501→        ], JSON_UNESCAPED_UNICODE);
502→
503→        \Log::info('[DifySlots] request', [
504→            'sfuser_id' => $sfuserId,
505→            'message' => $message,
506→            'conversation_id' => $conversationId,
507→            'previous_context' => $previousContext,
508→            'available_groups' => $availableGroups,
509→            'member_count' => count($availableMembers),
510→        ]);
511→
512→        $ch = curl_init($difyUrl);
513→        curl_setopt_array($ch, [
514→            CURLOPT_POST => true,
515→            CURLOPT_POSTFIELDS => $payload,
516→            CURLOPT_HTTPHEADER => [
517→                'Content-Type: application/json',
518→                'Authorization: Bearer '.$difyApiKey,
519→            ],
520→            CURLOPT_RETURNTRANSFER => true,
521→            CURLOPT_TIMEOUT => 120,
522→        ]);
523→
524→        $response = curl_exec($ch);
525→        $httpCode = curl_getinfo($ch, CURLINFO_HTTP_CODE);
526→        $curlError = $response === false ? curl_error($ch) : '';
527→        curl_close($ch);
528→
529→        if ($curlError) {
530→            \Log::error('[DifySlots] curl error', ['error' => $curlError]);
531→            return $this->responseJsonFail('AI 接口请求失败：'.$curlError);
532→        }
533→
534→        $difyResult = json_decode($response, true);
535→        if (!is_array($difyResult)) {
536→            \Log::error('[DifySlots] invalid response', ['raw' => mb_substr($response, 0, 1000)]);
537→            return $this->responseJsonFail('AI 接口返回异常');
538→        }
539→
540→        // Dify 错误响应
541→        if (isset($difyResult['message']) && !isset($difyResult['answer'])) {
542→            \Log::error('[DifySlots] dify error', ['result' => $difyResult]);
543→            return $this->responseJsonFail('AI 接口错误：'.$difyResult['message']);
544→        }
545→
546→        $newConversationId = $difyResult['conversation_id'] ?? '';
547→        $answer = $difyResult['answer'] ?? '';
548→
549→        \Log::info('[DifySlots] response', [
550→            'sfuser_id' => $sfuserId,
551→            'conversation_id' => $newConversationId,
552→            'answer_raw' => mb_substr($answer, 0, 1000),
553→            'http_code' => $httpCode,
554→        ]);
555→
556→        // 解析 LLM 输出的 JSON
557→        $slots = $this->parseSlotJson($answer);
558→
559→        \Log::info('[DifySlots] parsed', [
560→            'sfuser_id' => $sfuserId,
561→            'intent' => $slots['intent'],
562→            'slots_complete' => $slots['slots_complete'],
563→            'member_type' => $slots['member_type'],
564→            'members' => $slots['members'],
565→            'period' => $slots['period_start'].' ~ '.$slots['period_end'],
566→            'reply' => mb_substr($slots['reply'], 0, 200),
567→        ]);
568→
569→        return $this->responseJsonSuccess([
570→            'intent' => $slots['intent'],
571→            'slots_complete' => $slots['slots_complete'],
572→            'members' => $slots['members'],
573→            'member_type' => $slots['member_type'],
574→            'period_start' => $slots['period_start'],
575→            'period_end' => $slots['period_end'],
576→            'period_raw' => $slots['period_raw'],
577→            'reply' => $slots['reply'],
578→            'conversation_id' => $newConversationId,
579→        ]);
580→    }
