582→    // ----------------------------------------------------------------
583→    // 发送消息（SSE 流式）
584→    // ----------------------------------------------------------------
585→
586→    public function ask(Request $request): StreamedResponse
587→    {
588→        $sfuserId = Arr::get($request->input('sfuser_info'), 'id');
589→        if (!$this->inWhitelist($sfuserId)) {
590→            return $this->sseError('无权限');
591→        }
592→        $roleId = $request->input('role_id');
593→        $sessionId = $request->input('session_id');
594→        $message = $request->input('message');
595→        $reportContext = $request->input('report_context', '');
596→        $reportContextRaw = $request->input('report_context_raw', '');
597→        $history = $request->input('history', []);
598→
599→        // 解压 report_context（前端 gzip+base64 压缩后以 "gz:" 前缀标识）
600→        if (str_starts_with($reportContext, 'gz:')) {
601→            $decoded = base64_decode(substr($reportContext, 3), true);
602→            $reportContext = $decoded !== false ? (gzdecode($decoded) ?: $reportContext) : $reportContext;
603→        }
604→        // 去除多余空白（连续空行压缩为单空行），减少发给 AI 的 token
605→        $reportContext = preg_replace('/\n{3,}/', "\n\n", trim($reportContext));
606→        \Log::info('[DifyAsk] report_context size', [
607→            'bytes' => strlen($reportContext),
608→            'chars' => mb_strlen($reportContext),
609→        ]);
610→
611→        // 校验角色归属
612→        $role = DB::table('daily_report_ai_roles')
613→            ->where('id', $roleId)
614→            ->where('sfuser_id', $sfuserId)
615→            ->whereNull('deleted_at')
616→            ->first();
617→
618→        if (!$role) {
619→            return $this->sseError('角色不存在');
620→        }
621→
622→        // 创建或复用会话
623→        $difyConversationId = '';
624→        if (!$sessionId) {
625→            $title = mb_substr($message, 0, 20);
626→            $sessionId = DB::table('daily_report_ai_sessions')->insertGetId([
627→                'sfuser_id' => $sfuserId,
628→                'role_id' => $roleId,
629→                'title' => $title,
630→                'created_at' => now(),
631→                'updated_at' => now(),
632→            ]);
633→        } else {
634→            // 校验会话归属并取出 dify_conversation_id
635→            $sessionRow = DB::table('daily_report_ai_sessions')
636→                ->where('id', $sessionId)
637→                ->where('sfuser_id', $sfuserId)
638→                ->whereNull('deleted_at')
639→                ->first();
640→            if (!$sessionRow) {
641→                return $this->sseError('会话不存在');
642→            }
643→            $difyConversationId = $sessionRow->dify_conversation_id ?? '';
644→        }
645→
646→        // 解压 report_context_raw（与 report_context 相同的 gzip+base64 压缩格式）
647→        if (str_starts_with($reportContextRaw, 'gz:')) {
648→            $decoded = base64_decode(substr($reportContextRaw, 3), true);
649→            $reportContextRaw = $decoded !== false ? (gzdecode($decoded) ?: $reportContextRaw) : $reportContextRaw;
650→        }
651→
652→        // 保存同步日报上下文（如果有）—— 优先存原始 HTML，便于页面回显
653→        $contextToStore = !empty($reportContextRaw) ? $reportContextRaw : $reportContext;
654→        if (!empty($contextToStore)) {
655→            DB::table('daily_report_ai_messages')->insert([
656→                'session_id' => $sessionId,
657→                'role' => 'context',
658→                'content' => $contextToStore,
659→                'created_at' => now(),
660→            ]);
661→        }
662→
663→        // 保存用户消息
664→        DB::table('daily_report_ai_messages')->insert([
665→            'session_id' => $sessionId,
666→            'role' => 'user',
667→            'content' => $message,
668→            'created_at' => now(),
669→        ]);
670→
671→        // 更新会话时间
672→        DB::table('daily_report_ai_sessions')
673→            ->where('id', $sessionId)
674→            ->update(['updated_at' => now()]);
675→
676→        $capturedSessionId = $sessionId;
677→        $systemPrompt = $role->system_prompt;
678→
679→        return response()->stream(function () use (
680→            $message,
681→            $reportContext,
682→            $systemPrompt,
683→            $capturedSessionId,
684→            $difyConversationId
685→        ) {
686→            // 客户端断开后继续执行，确保 AI 回答能写入数据库
687→            ignore_user_abort(true);
688→
689→            // 首帧：发送 session_id
690→            $this->echoData(0, '', ['type' => 'session_id', 'session_id' => $capturedSessionId]);
691→
692→            // 构建发送给 Dify 的 query
693→            // system_prompt 通过 inputs 传给 Dify 工作流变量，不拼入 query
694→            // report_context 作为上下文附带在 query 中
695→            $queryParts = [];
696→            if (!empty($reportContext)) {
697→                $queryParts[] = "[日报数据]\n{$reportContext}";
698→            }
699→            $queryParts[] = $message;
700→            $query = implode("\n\n---\n\n", $queryParts);
701→
702→            // Dify 接口配置（测试地址和 key 已内置，生产环境通过 .env 覆盖）
703→            $difyBaseUrl = env('DIFY_BASE_URL', 'http://10.61.0.11:10880/v1');
704→            $difyApiKey = env('DIFY_API_KEY', 'app-vfZMS4mxMLlWkoyb88PmGDfv');
705→            $difyUrl = rtrim($difyBaseUrl, '/').'/chat-messages';
706→
707→            $payload = json_encode([
708→                'inputs' => ['system_prompt' => $systemPrompt ?: ' '],
709→                'query' => $query,
710→                'response_mode' => 'streaming',
711→                'conversation_id' => $difyConversationId ?: '',
712→                'user' => 'oa-session-'.$capturedSessionId,
713→            ], JSON_UNESCAPED_UNICODE);
714→
715→            $fullReply = '';
716→            $newDifyConversationId = '';
717→            $buffer = '';
718→
719→            \Log::info('[DifyAsk] request', [
720→                'url' => $difyUrl,
721→                'session' => $capturedSessionId,
722→                'user' => 'oa-session-'.$capturedSessionId,
723→            ]);
724→
725→            $rawResponse = '';
726→
727→            $ch = curl_init($difyUrl);
728→            curl_setopt_array($ch, [
729→                CURLOPT_POST => true,
730→                CURLOPT_POSTFIELDS => $payload,
731→                CURLOPT_HTTPHEADER => [
732→                    'Content-Type: application/json',
733→                    'Authorization: Bearer '.$difyApiKey,
734→                ],
735→                CURLOPT_RETURNTRANSFER => false,
736→                CURLOPT_TIMEOUT => 300,
737→                CURLOPT_WRITEFUNCTION => function ($curl, $data) use (&$fullReply, &$newDifyConversationId, &$buffer, &$rawResponse, $capturedSessionId) {
738→                    $rawResponse .= $data;
739→//                     \Log::info('[DifyAsk] raw chunk', ['session' => $capturedSessionId, 'bytes' => strlen($data), 'data' => mb_substr($data, 0, 500)]);
740→                    $buffer .= $data;
741→
742→                    // 按行处理，保证 SSE 事件完整性
743→                    while (($pos = strpos($buffer, "\n")) !== false) {
744→                        $line = rtrim(substr($buffer, 0, $pos), "\r");
745→                        $buffer = substr($buffer, $pos + 1);
746→
747→                        if (!str_starts_with($line, 'data: ')) {
748→                            continue;
749→                        }
750→
751→                        $decoded = json_decode(substr($line, 6), true);
752→                        if (!is_array($decoded)) {
753→                            continue;
754→                        }
755→
756→                        // 保存 conversation_id（首次或每帧均可能携带）
757→                        if (!empty($decoded['conversation_id'])) {
758→                            $newDifyConversationId = $decoded['conversation_id'];
759→                        }
760→
761→                        $event = $decoded['event'] ?? '';
762→
763→                        if ($event === 'message') {
764→                            // Chatbot 模式：流式 chunk
765→                            $chunk = $decoded['answer'] ?? '';
766→                            if ($chunk !== '') {
767→                                $fullReply .= $chunk;
768→                                $this->echoData(0, '', ['type' => 'chat', 'is_finished' => false, 'finish_reason' => '', 'content' => $chunk]);
769→                            }
770→                        } elseif ($event === 'text_chunk') {
771→                            // Workflow 流式模式：chunk 在 data.text
772→                            $chunk = $decoded['data']['text'] ?? '';
773→                            if ($chunk !== '') {
