926→    /**
927→     * 从 LLM 输出中解析槽位 JSON，兼容 markdown 代码块包裹.
928→     */
929→    private function parseSlotJson(string $text): array
930→    {
931→        $fallback = [
932→            'intent' => 'new_query',
933→            'slots_complete' => false,
934→            'members' => [],
935→            'member_type' => '',
936→            'period_start' => '',
937→            'period_end' => '',
938→            'period_raw' => '',
939→            'reply' => '抱歉没理解你的意思，请告诉我你想查哪个分组或具体成员的日报，以及查哪个时间段？',
940→        ];
941→
942→        if (!preg_match('/\{[\s\S]*\}/', $text, $matches)) {
943→            \Log::warning('[DifySlots] no JSON found in answer', ['text' => mb_substr($text, 0, 500)]);
944→            return $fallback;
945→        }
946→
947→        $data = json_decode($matches[0], true);
948→        if (!is_array($data)) {
949→            \Log::warning('[DifySlots] JSON parse failed', ['text' => mb_substr($matches[0], 0, 500)]);
950→            return $fallback;
951→        }
952→
953→        return [
954→            'intent' => $data['intent'] ?? 'new_query',
955→            'slots_complete' => !empty($data['slots_complete']),
956→            'members' => $data['members'] ?? [],
957→            'member_type' => $data['member_type'] ?? '',
958→            'period_start' => $data['period_start'] ?? '',
959→            'period_end' => $data['period_end'] ?? '',
960→            'period_raw' => $data['period_raw'] ?? '',
961→            'reply' => $data['reply'] ?? '',
962→        ];
963→    }
964→
965→    private function inWhitelist(int $sfuserId): bool
966→    {
967→        $setting = OaSetting::where('type', 'daily_report_ai')->select('ids', 'is_on')->first();
968→        if (!$setting || !$setting->is_on) {
969→            return false;
970→        }
971→        return in_array($sfuserId, $setting->ids ?? []);
972→    }
973→
974→    // ----------------------------------------------------------------
975→    // SSE 工具方法（同 OA echoData 规范）
976→    // ----------------------------------------------------------------
977→
978→    private function echoData(int $errCode, string $errMsg, array $data): void
979→    {
980→        echo 'data: '.json_encode(['error_code' => $errCode, 'error_msg' => $errMsg, 'data' => $data], JSON_UNESCAPED_UNICODE).PHP_EOL.PHP_EOL;
981→        ob_flush();
982→        flush();
983→    }
984→
985→    private function sseError(string $msg): StreamedResponse
986→    {
987→        return response()->stream(function () use ($msg) {
988→            $this->echoData(1, $msg, []);
989→        }, 200, [
990→            'Content-Type' => 'text/event-stream',
991→            'Cache-Control' => 'no-cache',
992→            'X-Accel-Buffering' => 'no',
993→        ]);
994→    }
