  7→
  8→class AiAnalysisService
  9→{
 10→    use ServiceTrait;
 11→
 12→    /**
 13→     * Blocking 模式：调用 Vertex AI，返回完整分析结果。
 14→     * 用于邮件发送场景。
 15→     */
 16→    public function analyze(string $content, string $systemPrompt): string
 17→    {
 18→        $endpoint = env('VERTEX_AI_ENDPOINT');
 19→        $apiKey = env('VERTEX_AI_API_KEY');
 20→        $model = env('VERTEX_AI_MODEL', 'google/gemini-2.0-flash');
 21→
 22→        $payload = json_encode([
 23→            'model' => $model,
 24→            'messages' => [
 25→                ['role' => 'system', 'content' => $systemPrompt],
 26→                ['role' => 'user', 'content' => $content],
 27→            ],
 28→            'stream' => false,
 29→        ], JSON_UNESCAPED_UNICODE);
 30→
 31→        Log::info('[AiAnalysis] blocking request', [
 32→            'content_len' => mb_strlen($content),
 33→            'prompt_len' => mb_strlen($systemPrompt),
 34→        ]);
 35→
 36→        $ch = curl_init($endpoint);
 37→        curl_setopt_array($ch, [
 38→            CURLOPT_POST => true,
 39→            CURLOPT_POSTFIELDS => $payload,
 40→            CURLOPT_HTTPHEADER => [
 41→                'Content-Type: application/json',
 42→                'Authorization: Bearer ' . $apiKey,
 43→            ],
 44→            CURLOPT_RETURNTRANSFER => true,
 45→            CURLOPT_TIMEOUT => 120,
 46→        ]);
 47→
 48→        $response = curl_exec($ch);
 49→        $httpCode = curl_getinfo($ch, CURLINFO_HTTP_CODE);
 50→        $curlError = $response === false ? curl_error($ch) : '';
 51→        curl_close($ch);
 52→
 53→        if ($curlError) {
 54→            Log::error('[AiAnalysis] curl error', ['error' => $curlError]);
 55→            return '';
 56→        }
 57→
 58→        $result = json_decode($response, true);
 59→        if (!is_array($result)) {
 60→            Log::error('[AiAnalysis] invalid response', ['raw' => mb_substr($response, 0, 1000)]);
 61→            return '';
 62→        }
 63→
 64→        $answer = Arr::get($result, 'choices.0.message.content', '');
 65→        Log::info('[AiAnalysis] blocking done', ['answer_len' => mb_strlen($answer)]);
 66→
 67→        return $answer;
 68→    }
 69→
 70→    /**
 71→     * Streaming 模式：调用 Vertex AI，通过回调逐 chunk 输出。
 72→     * 用于测试 Prompt 和前端 SSE 场景。
 73→     *
 74→     * @param string $content 日报内容
 75→     * @param string $systemPrompt AI Prompt
 76→     * @param callable $onChunk fn(string $chunk): void 每个 chunk 的回调
 77→     * @param array $history 可选的历史对话消息
 78→     */
 79→    public function analyzeStream(string $content, string $systemPrompt, callable $onChunk, array $history = []): string
 80→    {
 81→        $endpoint = env('VERTEX_AI_ENDPOINT');
 82→        $apiKey = env('VERTEX_AI_API_KEY');
 83→        $model = env('VERTEX_AI_MODEL', 'google/gemini-2.0-flash');
 84→
 85→        $messages = [
 86→            ['role' => 'system', 'content' => $systemPrompt],
 87→        ];
 88→        foreach ($history as $msg) {
 89→            $messages[] = ['role' => $msg['role'], 'content' => $msg['content']];
 90→        }
 91→        if (!empty($content)) {
 92→            $messages[] = ['role' => 'user', 'content' => $content];
 93→        }
 94→
 95→        $payload = json_encode([
 96→            'model' => $model,
 97→            'messages' => $messages,
 98→            'stream' => true,
 99→        ], JSON_UNESCAPED_UNICODE);
100→
101→        Log::info('[AiAnalysis] streaming request', [
102→            'content_len' => mb_strlen($content),
103→            'prompt_len' => mb_strlen($systemPrompt),
104→            'history_count' => count($history),
105→        ]);
106→
107→        $fullReply = '';
108→        $buffer = '';
109→
110→        $ch = curl_init($endpoint);
111→        curl_setopt_array($ch, [
112→            CURLOPT_POST => true,
113→            CURLOPT_POSTFIELDS => $payload,
114→            CURLOPT_HTTPHEADER => [
115→                'Content-Type: application/json',
116→                'Authorization: Bearer ' . $apiKey,
117→            ],
118→            CURLOPT_RETURNTRANSFER => false,
119→            CURLOPT_TIMEOUT => 300,
120→            CURLOPT_WRITEFUNCTION => function ($curl, $data) use (&$fullReply, &$buffer, $onChunk) {
121→                $buffer .= $data;
122→
123→                while (($pos = strpos($buffer, "\n")) !== false) {
124→                    $line = rtrim(substr($buffer, 0, $pos), "\r");
125→                    $buffer = substr($buffer, $pos + 1);
126→
127→                    if (!str_starts_with($line, 'data: ')) {
128→                        continue;
129→                    }
130→
131→                    $jsonStr = substr($line, 6);
132→                    if ($jsonStr === '[DONE]') {
133→                        continue;
134→                    }
135→
136→                    $decoded = json_decode($jsonStr, true);
137→                    if (!is_array($decoded)) {
138→                        continue;
139→                    }
140→
141→                    $chunk = Arr::get($decoded, 'choices.0.delta.content', '');
142→                    if ($chunk !== '') {
143→                        $fullReply .= $chunk;
144→                        $onChunk($chunk);
145→                    }
146→                }
147→
148→                return strlen($data);
149→            },
150→        ]);
151→
152→        curl_exec($ch);
153→        $curlError = curl_error($ch);
154→        curl_close($ch);
155→
156→        if ($curlError) {
157→            Log::error('[AiAnalysis] streaming curl error', ['error' => $curlError]);
158→        }
159→
160→        Log::info('[AiAnalysis] streaming done', ['reply_len' => mb_strlen($fullReply)]);
161→
162→        return $fullReply;
163→    }
164→}
