891→    private function parseSlotJson(string $text): array
892→    {
893→        $fallback = [
894→            'intent' => 'new_query',
895→            'slots_complete' => false,
896→            'members' => [],
897→            'member_type' => '',
898→            'period_start' => '',
899→            'period_end' => '',
900→            'period_raw' => '',
901→            'reply' => '抱歉没理解你的意思，请告诉我你想查哪个分组或具体成员的日报，以及查哪个时间段？',
902→        ];
903→
904→        if (!preg_match('/\{[\s\S]*\}/', $text, $matches)) {
905→            \Log::warning('[DifySlots] no JSON found in answer', ['text' => mb_substr($text, 0, 500)]);
906→            return $fallback;
907→        }
908→
909→        $data = json_decode($matches[0], true);
910→        if (!is_array($data)) {
911→            \Log::warning('[DifySlots] JSON parse failed', ['text' => mb_substr($matches[0], 0, 500)]);
912→            return $fallback;
913→        }
914→
915→        return [
916→            'intent' => $data['intent'] ?? 'new_query',
917→            'slots_complete' => !empty($data['slots_complete']),
918→            'members' => $data['members'] ?? [],
919→            'member_type' => $data['member_type'] ?? '',
920→            'period_start' => $data['period_start'] ?? '',
921→            'period_end' => $data['period_end'] ?? '',
922→            'period_raw' => $data['period_raw'] ?? '',
